{"code": "import json
import re

# Get the swift files result
swift_files = var_functions.query_db_24

# Check what we have
print('Type:', type(swift_files))
print('Length:', len(swift_files) if swift_files else 0)

# Find max copied file
max_copies = -1
max_file = None

if swift_files:
    for file in swift_files:
        desc = file['repo_data_description']
        # Extract number of copies
        copies = 0

        match = re.search(r'duplicated\s+(\d+)', desc)
        if not match:
            match = re.search(r'copied\s+(\d+)', desc)
        if not match:
            match = re.search(r'appearing\s+(\d+)', desc)
        if not match:
            match = re.search(r'repeated\s+(\d+)', desc)
        if not match:
            match = re.search(r'appears\s+(\d+)', desc)

        if match:
            copies = int(match.group(1))
            if copies > max_copies:
                max_copies = copies
                max_file = file

print('Max copies:', max_copies)
if max_file:
    print('Repo:', max_file['sample_repo_name'])
    print('File ID:', max_file['id'])

result = {'copies': max_copies, 'file': max_file}
print('__RESULT__:')
print(json.dumps(result))"}

